<body>
  <h1>CampusDigital</h1>

  <div class="game-container">
    <div class="header">
      <div id="timer">3:00</div>
      <div id="points">Punkte: 0</div>
    </div>

    <div class="process-list" id="processes"></div>

    <div class="controls">
      <button id="start-btn">Digitalisieren</button>
      <button id="reset-btn">Neustart</button>
    </div>

    <div class="feedback" id="feedback">
      Digitalisierung erfolgreich!
    </div>
  </div>

  <div class="game-over" id="game-over">
    <div class="result-card">
      <h2 id="result-title">Spiel beendet</h2>
      <div class="score-display" id="final-score">0</div>
      <p id="result-message"></p>
      <button onclick="resetGame()">Neustart</button>
    </div>
  </div>

  <script>
    const processes = [
      { name: "Prüfungsanmeldung", cost: 2, points: 10, progress: 0 },
      { name: "Ressourcenanfrage", cost: 3, points: 15, progress: 0 },
      { name: "Anmeldung Studiengang", cost: 4, points: 20, progress: 0 },
      { name: "Semesteranmeldung", cost: 3, points: 12, progress: 0 },
      { name: "Bewerbung Master", cost: 5, points: 25, progress: 0 },
      { name: "Forschungsantrag", cost: 6, points: 30, progress: 0 }
    ];

    let selected = [];
    let points = 0;
    let timeLeft = 180; // 3 Minuten in Sekunden
    let timer;
    let gameActive = false;

    function initGame() {
      const processList = document.getElementById("processes");
      processList.innerHTML = '';

      processes.forEach((p, i) => {
        const div = document.createElement("div");
        div.className = "process-card";
        div.id = `card-${i}`;
        div.innerHTML = `
          <input type="checkbox" id="proc-${i}" />
          <label for="proc-${i}" class="process-name">${p.name}</label>
          <span class="process-costs">(${p.cost} Min, ${p.points} Punkte)</span>
        `;
        processList.appendChild(div);
      });

      updateTimer();
      document.getElementById("points").innerText = `Punkte: ${points}`;
    }

    function updateTimer() {
      const minutes = Math.floor(timeLeft / 60);
      const seconds = timeLeft % 60;
      document.getElementById("timer").innerText = `${minutes}:${seconds < 10 ? '0' : ''}${seconds}`;

      if (timeLeft <= 30) {
        document.getElementById("timer").style.color = "#e74c3c";
      }

      if (timeLeft <= 0) {
        endGame(false);
      }
    }

    function startTimer() {
      clearInterval(timer);
      timer = setInterval(() => {
        timeLeft--;
        updateTimer();
        if (timeLeft <= 0) {
          clearInterval(timer);
        }
      }, 1000);
    }

    function selectProcess(index) {
      const checkbox = document.getElementById(`proc-${index}`);
      const card = document.getElementById(`card-${index}`);

      if (checkbox.checked) {
        selected.push(index);
        card.classList.add("selected");
      } else {
        selected = selected.filter(i => i !== index);
        card.classList.remove("selected");
      }
    }

    function startProcess() {
      if (!gameActive || timeLeft <= 0) return;

      let totalPoints = 0;
      let totalTime = 0;

      selected.forEach(index => {
        const process = processes[index];
        totalPoints += process.points;
        totalTime += process.cost;
      });

      points += totalPoints;
      document.getElementById("points").innerText = `Punkte: ${points}`;

      // Feedback
      document.getElementById("feedback").style.display = "block";
      setTimeout(() => {
        document.getElementById("feedback").style.display = "none";
      }, 1000);

      // Reset selection
      selected.forEach(index => {
        const checkbox = document.getElementById(`proc-${index}`);
        checkbox.checked = false;
        const card = document.getElementById(`card-${index}`);
        card.classList.remove("selected");
      });
      selected = [];

      // Check win condition
      if (points >= 50) {
        endGame(true);
      }
    }

    function endGame(success) {
      gameActive = false;
      clearInterval(timer);

      const gameOver = document.getElementById("game-over");
      const resultTitle = document.getElementById("result-title");
      const finalScore = document.getElementById("final-score");
      const resultMessage = document.getElementById("result-message");

      if (success) {
        resultTitle.innerText = "Gewonnen!";
        resultMessage.innerText = `Glückwunsch! Du hast ${points} Punkte erreicht und die Digitalisierung erfolgreich abgeschlossen.`;
      } else {
        resultTitle.innerText = "Verloren";
        resultMessage.innerText = `Zeit ist um. Du hast ${points} Punkte erreicht. Versuche es noch einmal!`;
      }

      finalScore.innerText = points;
      gameOver.classList.add("show");
    }

    function resetGame() {
      points = 0;
      timeLeft = 180;
      selected = [];
      gameActive = true;

      document.getElementById("points").innerText = `Punkte: ${points}`;
      document.getElementById("game-over").classList.remove("show");

      initGame();
      startTimer();

      // Add event listeners to checkboxes
      document.querySelectorAll('input[type="checkbox"]').forEach((cb, i) => {
        cb.removeEventListener("change", () => selectProcess(i));
        cb.addEventListener("change", () => selectProcess(i));
      });

      // Button listeners
      document.getElementById("start-btn").onclick = startProcess;
      document.getElementById("reset-btn").onclick = resetGame;
    }

    window.onload = () => {
      initGame();
      startTimer();

      // Add event listeners to checkboxes
      document.querySelectorAll('input[type="checkbox"]').forEach((cb, i) => {
        cb.addEventListener("change", () => selectProcess(i));
      });

      // Button listeners
      document.getElementById("start-btn").onclick = startProcess;
      document.getElementById("reset-btn").onclick = resetGame;

      gameActive = true;
    };
  </script>
</body>
</html>
