<body>
  <h1>Campus-Optimierer</h1>
  <div class="game-container">
    <div class="instructions">
      Automatisiere Prozesse durch Eingabe von Punkten (0–10). Je höher die Punktezahl, desto mehr Wert wird automatisiert.
    </div>

    <div class="status-bar">
      <span class="timer">Zeit: <span id="time">2:00</span></span>
      <span class="points">Punkte: <span id="score">0</span></span>
      <span id="status">Bereit</span>
    </div>

    <table id="processTable">
      <thead>
        <tr>
          <th>Prozess</th>
          <th>Zeit (min)</th>
          <th>Wert</th>
          <th>Automatisierungspunkte</th>
        </tr>
      </thead>
      <tbody id="processList">
      </tbody>
    </table>

    <div class="controls">
      <button id="startBtn">Spiel starten</button>
      <button id="restartBtn">Neustart</button>
    </div>

    <div class="summary" id="summary">
      <h2>Spiel beendet!</h2>
      <p>Erreichte Punkte: <span id="finalScore">0</span></p>
      <p>Prozentualer Erfolg: <span id="successRate">0%</span></p>
    </div>
  </div>

  <script>
    const processes = [
      { name: "Anmeldeformular", time: 2, value: 15 },
      { name: "Genehmigungen", time: 3, value: 20 },
      { name: "Abrechnungen", time: 4, value: 25 },
      { name: "Dokumentation", time: 2, value: 10 },
      { name: "Benutzeranmeldung", time: 1, value: 8 },
      { name: "Zugangskontrolle", time: 3, value: 18 }
    ];

    let timer;
    let timeLeft = 120; // 2 Minuten in Sekunden
    let score = 0;
    let gameActive = false;

    const timeElement = document.getElementById('time');
    const scoreElement = document.getElementById('score');
    const statusElement = document.getElementById('status');
    const processListElement = document.getElementById('processList');
    const startBtn = document.getElementById('startBtn');
    const restartBtn = document.getElementById('restartBtn');
    const summaryElement = document.getElementById('summary');
    const finalScoreElement = document.getElementById('finalScore');
    const successRateElement = document.getElementById('successRate');

    function formatTime(seconds) {
      const mins = Math.floor(seconds / 60);
      const secs = seconds % 60;
      return `${mins}:${secs < 10 ? '0' : ''}${secs}`;
    }

    function updateTimer() {
      timeLeft--;
      timeElement.textContent = formatTime(timeLeft);

      if (timeLeft <= 0) {
        endGame();
      }
    }

    function startGame() {
      gameActive = true;
      statusElement.textContent = "Laufend";
      timeLeft = 120;
      score = 0;
      updateTimer();
      timer = setInterval(updateTimer, 1000);
      renderProcesses();
      summaryElement.classList.remove('show');
    }

    function restartGame() {
      clearInterval(timer);
      startGame();
    }

    function endGame() {
      gameActive = false;
      clearInterval(timer);
      statusElement.textContent = "Beendet";

      // Berechne den Erfolg
      const totalValue = processes.reduce((sum, p) => sum + p.value, 0);
      const successRate = totalValue > 0 ? Math.round((score / totalValue) * 100) : 0;

      finalScoreElement.textContent = score;
      successRateElement.textContent = `${successRate}%`;

      summaryElement.classList.add('show');
    }

    function renderProcesses() {
      processListElement.innerHTML = '';
      processes.forEach((process, index) => {
        const row = document.createElement('tr');
        row.innerHTML = `
          <td>${process.name}</td>
          <td>${process.time}</td>
          <td>${process.value}</td>
          <td><input type="number" min="0" max="10" value="0" data-index="${index}"></td>
        `;
        processListElement.appendChild(row);
      });

      // Füge Event Listener zu den Inputs hinzu
      document.querySelectorAll('#processList input').forEach(input => {
        input.addEventListener('input', calculateScore);
      });
    }

    function calculateScore() {
      if (!gameActive) return;

      let total = 0;
      const inputs = document.querySelectorAll('#processList input');

      inputs.forEach((input, index) => {
        // Eingabe validieren: Wert zwischen 0 und 10
        let value = parseInt(input.value) || 0;
        value = Math.min(10, Math.max(0, value));

        // Aktualisiere den Eingabewert im DOM, falls er außerhalb war
        input.value = value;

        const process = processes[index];
        if (value > 0) {
          // Neue Formel: Automatisierungswert bestimmt den Anteil des Prozesswerts
          total += Math.round(process.value * (value / 10));
        }
      });

      score = total;
      scoreElement.textContent = score;
    }

    startBtn.addEventListener('click', startGame);
    restartBtn.addEventListener('click', restartGame);

    // Initial render
    renderProcesses();
  </script>
</body>
</html>
